fn roll_table(key: &str, rarity: i32) -> Option<&'static [(i32, u8)]> {
    match (rarity, key) {
        (4, "atk") => Some(RT_4_ATK),
        (4, "atk_") => Some(RT_4_ATK_PCT),
        (4, "critDMG_") => Some(RT_4_CRITDMG_PCT),
        (4, "critRate_") => Some(RT_4_CRITRATE_PCT),
        (4, "def") => Some(RT_4_DEF),
        (4, "def_") => Some(RT_4_DEF_PCT),
        (4, "eleMas") => Some(RT_4_ELEMAS),
        (4, "enerRech_") => Some(RT_4_ENERRECH_PCT),
        (4, "hp") => Some(RT_4_HP),
        (4, "hp_") => Some(RT_4_HP_PCT),
        (5, "atk") => Some(RT_5_ATK),
        (5, "atk_") => Some(RT_5_ATK_PCT),
        (5, "critDMG_") => Some(RT_5_CRITDMG_PCT),
        (5, "critRate_") => Some(RT_5_CRITRATE_PCT),
        (5, "def") => Some(RT_5_DEF),
        (5, "def_") => Some(RT_5_DEF_PCT),
        (5, "eleMas") => Some(RT_5_ELEMAS),
        (5, "enerRech_") => Some(RT_5_ENERRECH_PCT),
        (5, "hp") => Some(RT_5_HP),
        (5, "hp_") => Some(RT_5_HP_PCT),
        _ => None,
    }
}
